import requests, tarfile, io, re
repos=['galaxy4552/SleepingOwl-legacy','04-jj/law_assistant','LGCCCCCCC/PDF-edu-smart','lveyond/knowledge-base']
pat=re.compile(r'bge-small-zh-v1\.5|BAAI/bge-small-zh-v1\.5|bge-small-zh',re.I)
for repo in repos:
    url=f'https://api.github.com/repos/{repo}/tarball'
    print('\n==',repo)
    try:
        r=requests.get(url,timeout=40)
        print('status',r.status_code,'size',len(r.content))
        if r.status_code!=200:
            print(r.text[:200]); continue
        tf=tarfile.open(fileobj=io.BytesIO(r.content),mode='r:gz')
        hits=0
        for m in tf.getmembers():
            if not m.isfile() or m.size>2_000_000:
                continue
            name=m.name
            if not any(name.endswith(ext) for ext in ['.py','.md','.txt','.yaml','.yml','.json','.toml','.ini','.ipynb','.env','.cfg']):
                continue
            f=tf.extractfile(m)
            if not f:
                continue
            try:
                txt=f.read().decode('utf-8',errors='ignore')
            except Exception:
                continue
            if pat.search(txt):
                print('hit file',name)
                for line in txt.splitlines():
                    if pat.search(line):
                        print('  ',line[:180])
                        break
                hits += 1
                if hits>=5:
                    break
        if hits==0:
            print('no hits')
    except Exception as e:
        print('err',e)
